package test.rice.obj;

import main.rice.obj.PyBoolObj;
import main.rice.obj.PyCharObj;
import main.rice.obj.PyDictObj;
import main.rice.obj.PyIntObj;
import main.rice.obj.PyListObj;
import main.rice.obj.PySetObj;
import main.rice.obj.PyStringObj;
import main.rice.obj.PyTupleObj;
import org.junit.jupiter.api.Test;

import java.util.Arrays;
import java.util.LinkedHashMap;
import java.util.LinkedHashSet;
import java.util.Map;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotEquals;

class PyObjAgentTest {
    @Test
    void testEqualityRequiresSameConcreteType() {
        assertEquals(new PyIntObj(3), new PyIntObj(3));
        assertNotEquals(new PyIntObj(3), new PyBoolObj(true));
        assertNotEquals(
            new PyListObj<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2))),
            new PyTupleObj<>(Arrays.asList(new PyIntObj(1), new PyIntObj(2)))
        );
    }

    @Test
    void testHashCodeMatchesEquality() {
        Map<PyIntObj, PyStringObj> left = new LinkedHashMap<>();
        left.put(new PyIntObj(1), new PyStringObj("a"));
        Map<PyIntObj, PyStringObj> right = new LinkedHashMap<>();
        right.put(new PyIntObj(1), new PyStringObj("a"));

        PyDictObj<PyIntObj, PyStringObj> leftDict = new PyDictObj<>(left);
        PyDictObj<PyIntObj, PyStringObj> rightDict = new PyDictObj<>(right);

        assertEquals(leftDict, rightDict);
        assertEquals(leftDict.hashCode(), rightDict.hashCode());
    }

    @Test
    void testStringAndCharEscaping() {
        assertEquals("'a\\tb\\nc\\'\\\\'", new PyStringObj("a\tb\nc'\\").toString());
        assertEquals("'\\n'", new PyCharObj('\n').toString());
    }

    @Test
    void testSetAndTupleFormattingEdgeCases() {
        assertEquals("(1,)", new PyTupleObj<>(Arrays.asList(new PyIntObj(1))).toString());
        assertEquals("set()", new PySetObj<>(new LinkedHashSet<>()).toString());
    }
}

package main.rice.obj;

import java.util.ArrayList;
import java.util.List;

public class PyListObj<T extends APyObj<?>> extends AIterablePyObj<List<T>> {
    public PyListObj(List<T> value) {
        super(new ArrayList<>(value));
    }

    @Override
    public String toString() {
        return "[" + this.joinIterable(this.getValue()) + "]";
    }
}

package main.rice.obj;

import java.util.Objects;

public abstract class APyObj<T> {
    private final T value;

    protected APyObj(T value) {
        this.value = value;
    }

    public T getValue() {
        return this.value;
    }

    @Override
    public boolean equals(Object other) {
        if (this == other) {
            return true;
        }
        if (other == null || this.getClass() != other.getClass()) {
            return false;
        }
        APyObj<?> that = (APyObj<?>) other;
        return Objects.equals(this.value, that.value);
    }

    @Override
    public int hashCode() {
        return Objects.hash(this.getClass(), this.value);
    }

    @Override
    public abstract String toString();
}

package main.rice.obj;

public class PyIntObj extends APyObj<Integer> {
    public PyIntObj(int value) {
        super(value);
    }

    @Override
    public String toString() {
        return Integer.toString(this.getValue());
    }
}

package main.rice.obj;

import java.util.Iterator;

public abstract class AIterablePyObj<T> extends APyObj<T> {
    protected AIterablePyObj(T value) {
        super(value);
    }

    protected String joinIterable(Iterable<?> values) {
        StringBuilder builder = new StringBuilder();
        Iterator<?> iterator = values.iterator();
        while (iterator.hasNext()) {
            builder.append(iterator.next());
            if (iterator.hasNext()) {
                builder.append(", ");
            }
        }
        return builder.toString();
    }
}

package main.rice.obj;

import java.util.ArrayList;
import java.util.List;

public class PyStringObj extends AIterablePyObj<List<PyCharObj>> {
    public PyStringObj(String value) {
        super(toCharList(value));
    }

    private static List<PyCharObj> toCharList(String value) {
        List<PyCharObj> chars = new ArrayList<>();
        for (int i = 0; i < value.length(); i++) {
            chars.add(new PyCharObj(value.charAt(i)));
        }
        return chars;
    }

    static String escapeChar(char c) {
        switch (c) {
            case '\\':
                return "\\\\";
            case '\'':
                return "\\'";
            case '\n':
                return "\\n";
            case '\t':
                return "\\t";
            case '\r':
                return "\\r";
            default:
                return Character.toString(c);
        }
    }

    @Override
    public String toString() {
        StringBuilder builder = new StringBuilder("'");
        for (PyCharObj ch : this.getValue()) {
            builder.append(escapeChar(ch.getValue()));
        }
        builder.append("'");
        return builder.toString();
    }
}

