package main.rice.obj;

import java.util.LinkedHashSet;
import java.util.Set;

public class PySetObj<T extends APyObj<?>> extends AIterablePyObj<Set<T>> {
    public PySetObj(Set<T> value) {
        super(new LinkedHashSet<>(value));
    }

    @Override
    public String toString() {
        if (this.getValue().isEmpty()) {
            return "set()";
        }
        return "{" + this.joinIterable(this.getValue()) + "}";
    }
}

package main.rice.obj;

public class PyBoolObj extends APyObj<Boolean> {
    public PyBoolObj(boolean value) {
        super(value);
    }

    @Override
    public String toString() {
        return this.getValue() ? "True" : "False";
    }
}

package main.rice.obj;

import java.util.ArrayList;
import java.util.List;

public class PyTupleObj<T extends APyObj<?>> extends AIterablePyObj<List<T>> {
    public PyTupleObj(List<T> value) {
        super(new ArrayList<>(value));
    }

    @Override
    public String toString() {
        if (this.getValue().isEmpty()) {
            return "()";
        }
        if (this.getValue().size() == 1) {
            return "(" + this.getValue().get(0) + ",)";
        }
        return "(" + this.joinIterable(this.getValue()) + ")";
    }
}

package main.rice.obj;

public class PyCharObj extends APyObj<Character> {
    public PyCharObj(char value) {
        super(value);
    }

    @Override
    public String toString() {
        return "'" + PyStringObj.escapeChar(this.getValue()) + "'";
    }
}

package main.rice.obj;

import java.util.LinkedHashMap;
import java.util.Map;

public class PyDictObj<K extends APyObj<?>, V extends APyObj<?>> extends APyObj<Map<K, V>> {
    public PyDictObj(Map<K, V> value) {
        super(new LinkedHashMap<>(value));
    }

    @Override
    public String toString() {
        StringBuilder builder = new StringBuilder("{");
        boolean first = true;
        for (Map.Entry<K, V> entry : this.getValue().entrySet()) {
            if (!first) {
                builder.append(", ");
            }
            builder.append(entry.getKey()).append(": ").append(entry.getValue());
            first = false;
        }
        builder.append("}");
        return builder.toString();
    }
}

